// 接收正EV推播的信號，寫入 Google Sheet signal_tracking 分頁
const body = $input.first().json.body || $input.first().json;
const signals = body.signals || [];
const tracking = body.tracking || {};
const raw = body.raw || [];

if (signals.length === 0) {
  return [{ json: { status: 'no_signals', timestamp: new Date().toISOString() } }];
}

// 為每筆信號建立追蹤記錄
const rows = [];
for (const sig of signals) {
  // 找到對應的 raw 數據
  const rawSym = raw.find(r => r.ticker === sig.symbol) || {};
  const spreads = rawSym.spreads || [];
  const matchSpread = spreads.find(s => s.strategy === sig.strategy) || {};

  rows.push({
    tracking_id: tracking.id || `sig-${Date.now()}`,
    push_time: tracking.pushTime || new Date().toISOString(),
    symbol: sig.symbol,
    strategy: sig.strategy,
    module: sig.module,
    direction: sig.bias || rawSym.direction || '',
    direction_score: rawSym.directionScore || 0,
    market_regime: tracking.marketRegime || '',
    vix: tracking.vix || '',

    // 技術面快照
    rsi: rawSym.rsi || '',
    ma20: rawSym.ma20 || '',
    macd_cross: rawSym.macd?.cross || '',
    iv_skew: rawSym.ivSkew || '',
    ivr: rawSym.ivr || '',
    support: rawSym.support || '',
    resistance: rawSym.resistance || '',
    volume_ratio: rawSym.volumeRatio || '',
    volume_spike: rawSym.volumeSpike || false,

    // 策略參數
    short_strike: matchSpread.shortStrike || sig.short_strike || '',
    long_strike: matchSpread.longStrike || sig.long_strike || '',
    dte: matchSpread.dte || '',
    exp_date: matchSpread.expDate || '',
    credit: sig.credit_received || matchSpread.credit || '',
    debit: sig.debit_paid || matchSpread.debit || '',
    ev: matchSpread.ev || '',
    kelly: matchSpread.kelly || '',
    win_rate: matchSpread.winRate || '',
    delta: matchSpread.shortDelta || '',
    take_profit: matchSpread.takeProfit || '',
    stop_loss: matchSpread.stopLoss || '',
    support_aligned: matchSpread.supportAligned || false,
    resistance_aligned: matchSpread.resistanceAligned || false,
    vega_note: matchSpread.vegaNote || '',

    // 結果（待填入）
    outcome: '',           // WIN / LOSS / STOPPED / EXPIRED
    actual_pnl: '',        // 實際盈虧
    exit_price: '',        // 出場價格
    exit_date: '',         // 出場日期
    exit_reason: '',       // 止盈/止損/到期/手動
    days_held: '',         // 持有天數

    // 版本
    version: 'v3.4',
  });
}

return rows.map(r => ({ json: r }));

// 計算各層的信號正確率
const allSignals = $('Read All Signals').all().map(i => i.json);
const settled = allSignals.filter(s => s.outcome && s.outcome !== '');
const wins = settled.filter(s => s.outcome === 'WIN');
const losses = settled.filter(s => s.outcome === 'LOSS' || s.outcome === 'STOPPED');

const total = settled.length;
const winCount = wins.length;
const lossCount = losses.length;
const winRate = total > 0 ? (winCount / total * 100).toFixed(1) : 'N/A';

// 按策略分組
const byStrategy = {};
for (const s of settled) {
  const key = s.strategy || 'unknown';
  if (!byStrategy[key]) byStrategy[key] = { wins: 0, losses: 0, total: 0, totalPnl: 0 };
  byStrategy[key].total++;
  if (s.outcome === 'WIN') byStrategy[key].wins++;
  else byStrategy[key].losses++;
  byStrategy[key].totalPnl += parseFloat(s.actual_pnl) || 0;
}

// 按方向分組
const byDirection = {};
for (const s of settled) {
  const key = s.direction || 'unknown';
  if (!byDirection[key]) byDirection[key] = { wins: 0, losses: 0, total: 0 };
  byDirection[key].total++;
  if (s.outcome === 'WIN') byDirection[key].wins++;
  else byDirection[key].losses++;
}

// 按 market regime 分組
const byRegime = {};
for (const s of settled) {
  const key = s.market_regime || 'unknown';
  if (!byRegime[key]) byRegime[key] = { wins: 0, losses: 0, total: 0 };
  byRegime[key].total++;
  if (s.outcome === 'WIN') byRegime[key].wins++;
  else byRegime[key].losses++;
}

// 各篩選條件的正確率
const filterAccuracy = {
  support_aligned: { yes: { w: 0, l: 0 }, no: { w: 0, l: 0 } },
  volume_spike: { yes: { w: 0, l: 0 }, no: { w: 0, l: 0 } },
  vega_favorable: { yes: { w: 0, l: 0 }, no: { w: 0, l: 0 } },
};

for (const s of settled) {
  const isWin = s.outcome === 'WIN';
  // 支撐對齊
  const sa = s.support_aligned === true || s.support_aligned === 'true';
  filterAccuracy.support_aligned[sa ? 'yes' : 'no'][isWin ? 'w' : 'l']++;
  // 成交量爆量
  const vs = s.volume_spike === true || s.volume_spike === 'true';
  filterAccuracy.volume_spike[vs ? 'yes' : 'no'][isWin ? 'w' : 'l']++;
  // Vega 效益
  const vf = (s.vega_note || '').includes('✅');
  filterAccuracy.vega_favorable[vf ? 'yes' : 'no'][isWin ? 'w' : 'l']++;
}

return [{ json: {
  summary: {
    total_signals: allSignals.length,
    settled: total,
    pending: allSignals.length - total,
    wins: winCount,
    losses: lossCount,
    win_rate: winRate + '%',
    total_pnl: settled.reduce((sum, s) => sum + (parseFloat(s.actual_pnl) || 0), 0).toFixed(2),
  },
  by_strategy: Object.entries(byStrategy).map(([k, v]) => ({
    strategy: k, ...v, winRate: (v.wins / v.total * 100).toFixed(1) + '%'
  })),
  by_direction: Object.entries(byDirection).map(([k, v]) => ({
    direction: k, ...v, winRate: (v.wins / v.total * 100).toFixed(1) + '%'
  })),
  by_regime: Object.entries(byRegime).map(([k, v]) => ({
    regime: k, ...v, winRate: (v.wins / v.total * 100).toFixed(1) + '%'
  })),
  filter_accuracy: filterAccuracy,
  generated_at: new Date().toISOString(),
} }];

